import React from 'react'
import ReactDOM from 'react-dom'
import Idle from 'react-idle'
import './index.css'
import Home from './containers/Home'

ReactDOM.render((
  <Idle
    timeout={3000}
    render={({ idle }) =>
      <div>
        {idle
          ? <h1 style={{margin: 0, padding: 0}}>{'Hola Mundo!'}</h1>
          : <Home />
        }
      </div>
    }
  />
), document.getElementById('root'))



