import React from 'react'
import './style.css'
import {
  IconGit,
  IconGmail,
  IconLinkedin,
  IconTwit
} from '../../assets'

const IconLink = ({icon, alt, link, titleLink}) => (
  <a href={link}>
    <img src={icon} alt={alt} target='_blank' />
    <span>{titleLink}</span>
  </a>
)

const Section = () => (
  <section className='links'>
    <IconLink icon={IconGit} alt={'icon-git'} link={'#'} titleLink={'oscaroceguera'} />
    <IconLink icon={IconLinkedin} alt={'icon-linkedin'} link={'#'} titleLink={'Oscar E. Oceguera Bibriesca'} />
    <IconLink icon={IconGmail} alt={'icon-gmail'} link={'#'} titleLink={'oscaroceguera@gmail.com'} />
    <IconLink icon={IconTwit} alt={'icon-twit'} link={'#'} titleLink={'@oscarOcegueraB'} />
  </section>
)

export default Section



